
import React, { useState } from "react";
import { cn } from "@/lib/utils";
import { useToast } from "@/components/ui/use-toast";
import AnimatedContainer from "./AnimatedContainer";
import CameraCapture from "./image-upload/CameraCapture";
import ImagePreview from "./image-upload/ImagePreview";
import UploadInterface from "./image-upload/UploadInterface";

interface ImageUploadProps {
  onImageSelected: (file: File) => void;
  className?: string;
}

const ImageUpload: React.FC<ImageUploadProps> = ({
  onImageSelected,
  className,
}) => {
  const [preview, setPreview] = useState<string | null>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [isImageLoaded, setIsImageLoaded] = useState(false);
  const [isCameraActive, setIsCameraActive] = useState(false);
  const { toast } = useToast();

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const processFile = (file: File) => {
    if (!file.type.startsWith("image/")) {
      console.error("File is not an image");
      toast({
        title: "Invalid file",
        description: "Please upload an image file",
        variant: "destructive",
      });
      return;
    }
    
    setIsLoading(true);
    setIsImageLoaded(false);
    
    const reader = new FileReader();
    reader.onload = () => {
      setPreview(reader.result as string);
      onImageSelected(file);
    };
    reader.readAsDataURL(file);
  };

  const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
    e.preventDefault();
    setIsDragging(false);
    
    const file = e.dataTransfer.files?.[0];
    if (file) {
      processFile(file);
    }
  };

  const handleRemoveImage = () => {
    setPreview(null);
    setIsImageLoaded(false);
  };

  const handleImageLoad = () => {
    setIsLoading(false);
    setIsImageLoaded(true);
  };

  const startCamera = () => {
    setIsCameraActive(true);
  };

  const stopCamera = () => {
    setIsCameraActive(false);
  };

  const handleCaptureImage = (file: File) => {
    stopCamera();
    processFile(file);
  };

  return (
    <div className={cn("w-full", className)}>
      <AnimatedContainer animationType="slide-up">
        <div
          className={cn(
            "relative rounded-xl border-2 border-dashed transition-all duration-300 overflow-hidden",
            isDragging
              ? "border-primary bg-primary/5"
              : "border-border bg-background/30",
            preview || isCameraActive ? "h-[350px]" : "h-[250px]",
            "flex flex-col items-center justify-center"
          )}
          onDragOver={handleDragOver}
          onDragLeave={handleDragLeave}
          onDrop={handleDrop}
        >
          {isCameraActive ? (
            <CameraCapture 
              onCapture={handleCaptureImage}
              onCancel={stopCamera}
            />
          ) : preview ? (
            <ImagePreview
              imageUrl={preview}
              isLoading={isLoading}
              onRemove={handleRemoveImage}
              onImageLoad={handleImageLoad}
            />
          ) : (
            <UploadInterface
              onFileSelect={handleFileChange}
              onCameraStart={startCamera}
            />
          )}
        </div>
      </AnimatedContainer>
    </div>
  );
};

export default ImageUpload;
